"""Dataset orientado a entrenamiento sobre imagen."""from __future__ import annotationsfrom pathlib import Pathfrom typing import Anyimport numpy as npimport pandas as pdfrom federated_skin.data.metadata import (    attach_image_paths,    filter_existing_images,    load_metadata,)from federated_skin.vision.preprocessing import load_image, normalize_image, preprocess_image, resize_imagefrom federated_skin.vision.segmentation import segment_lesionclass ImageDataset:    """    Representa un dataset basado en imágenes a partir de la metadata.    Parameters    ----------    metadata_path : Path        Ruta al fichero CSV con la metadata.    images_dir : Path        Directorio donde se encuentran las imágenes.    image_size : int        Tamaño cuadrado de salida.    image_input_mode : str        Modo de entrada de imagen. Valores soportados:        - "original"        - "preprocessed"        - "segmented"        - "preprocessed_plus_mask"    """    def __init__(        self,        metadata_path: Path,        images_dir: Path,        image_size: int = 224,        image_input_mode: str = "preprocessed",    ) -> None:        self.metadata_path = metadata_path        self.images_dir = images_dir        self.image_size = image_size        self.image_input_mode = image_input_mode        self.df = self._build_index()    def _build_index(self) -> pd.DataFrame:        """        Construye un índice interno con metadata y rutas válidas de imagen.        Returns        -------        pd.DataFrame            DataFrame con metadata y columna image_path.        """        df = load_metadata(self.metadata_path)        df = attach_image_paths(df, self.images_dir)        df = filter_existing_images(df)        return df    def to_dataframe(self) -> pd.DataFrame:        """        Devuelve una copia del índice interno del dataset.        Returns        -------        pd.DataFrame            DataFrame con metadata y rutas de imagen.        """        return self.df.copy()    def __len__(self) -> int:        """        Devuelve el número de muestras disponibles.        Returns        -------        int            Número de imágenes válidas.        """        return len(self.df)    def get_sample(self, index: int) -> dict[str, Any]:        """        Devuelve una muestra del dataset según el modo configurado.        Parameters        ----------        index : int            Índice de la muestra.        Returns        -------        dict[str, Any]            Diccionario con:            - image_id            - dx            - image        """        row = self.df.iloc[index]        original_image = self._load_original_image(row.image_path)        preprocessed_image = preprocess_image(row.image_path, self.image_size)        if self.image_input_mode == "original":            output_image = original_image        elif self.image_input_mode == "preprocessed":            output_image = preprocessed_image        elif self.image_input_mode == "segmented":            segmentation_result = segment_lesion(preprocessed_image)            output_image = segmentation_result["segmented_image"].astype(np.float32)        elif self.image_input_mode == "preprocessed_plus_mask":            segmentation_result = segment_lesion(preprocessed_image)            mask = segmentation_result["mask"].astype(np.float32)            mask = np.expand_dims(mask, axis=-1)            output_image = np.concatenate([preprocessed_image, mask], axis=-1)        else:            raise ValueError(                f"Modo de entrada de imagen no soportado: {self.image_input_mode}"            )        return {            "image_id": row.image_id,            "dx": row.dx,            "image": output_image,        }    def _load_original_image(self, image_path: Path) -> np.ndarray:        """        Carga la imagen original, la redimensiona y la normaliza.        Parameters        ----------        image_path : Path            Ruta de la imagen.        Returns        -------        np.ndarray            Imagen original preparada para entrada a modelo.        """        image = load_image(image_path)        image = resize_image(image, self.image_size)        image = normalize_image(image)        return image